onClick:
{{
(
  appsmith.store.modoPA === "MODIFICAR"
    ? qryPAModificar.run()
    : qryPAGuardar.run()
)
.then(async () => {

  await storeValue(
    "idPAImpresion",
    appsmith.store.modoPA === "MODIFICAR"
      ? appsmith.store.idPAModificar
      : qryPAGuardar.data?.[0]?.id_pago
  );

  await storeValue(
    "ultimoPACreado",
    appsmith.store.modoPA === "MODIFICAR"
      ? appsmith.store.encabezadoPA?.numero_pago
      : qryPAGuardar.data?.[0]?.numero_pago
  );

  showAlert(
    "Pago " +
    (
      appsmith.store.modoPA === "MODIFICAR"
        ? appsmith.store.encabezadoPA?.numero_pago
        : qryPAGuardar.data?.[0]?.numero_pago
    ) +
    (
      appsmith.store.modoPA === "MODIFICAR"
        ? " modificado correctamente."
        : " creado correctamente."
    ),
    "success"
  );

  // Salir de modo modificar
  await storeValue("modoPA", null);
  await storeValue("idPAModificar", null);
  await storeValue("encabezadoPA", null);
  await storeValue("detallePA", []);

  // Limpiar pantalla
  await JS_PA.nuevo();

})
.catch((e) => {

  showAlert(
    e.message,
    "error"
  );

});
}}
